sql:
SELECT COUNT(candidate_id)
FROM candidates
WHERE election_id = (
    SELECT MAX(election_id)
    FROM elections
);

SELECT COUNT(election_id) AS total_elections, 
       AVG((julianday(early_voting_end_date) - julianday(early_voting_start_date)) * 24) AS average_early_voting_hours
FROM elections;

SELECT name, SUM(votes) as total_votes
FROM candidates
GROUP BY name;

SELECT candidates.name, parties.party_name
FROM candidates
JOIN parties ON candidates.party_id = parties.party_id;

SELECT COUNT(*) 
FROM candidates 
WHERE party_id = 1 AND votes > (SELECT AVG(votes) FROM candidates WHERE party_id = 1);

SELECT gender, COUNT(*) AS count
FROM voters
GROUP BY gender;

SELECT name
FROM candidates
WHERE percentage > (SELECT AVG(percentage) FROM candidates);

SELECT SUM(votes) AS total_votes
FROM candidates
WHERE election_id = (
  SELECT MAX(election_id)
  FROM elections
);

SELECT voters_cast AS total_voters_cast
FROM voter_turnout
WHERE election_id = 1;

SELECT name, votes
FROM candidates
ORDER BY votes DESC;

SELECT votes
FROM candidates
WHERE candidate_id = 1 AND election_id = 1;
